#include<bits/stdc++.h>
using namespace std;
long long n,a[100005];
deque<int>dq;
int main()
{
	// freopen("2.in","r",stdin);
	// freopen("2.out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	for(int i=1;i<=n;i++){
		dq.push_back(a[i]);
	}
	int num=0;
	while(!dq.empty()){
		num+=dq.front();
		dq.pop_front();
		if(!dq.empty()){
			num+=dq.front();
			dq.pop_front();
			dq.push_front(num);
		}
	}
	cout<<num/2;
	return 0;
}
